official_example:
%%{init: {"theme": "neutral"}}%%
classDiagram
    class Vehicle {
        +move()
    }
    class Car {
        -engine: String
        +drive()
    }
    Vehicle <|-- Car

requirementDiagram
    requirement req_lock {
        id: 1.1
        text: "当速度超过20km/h时自动锁定车门"
        risk: medium
        verifyMethod: test
    }
    element actuator {
        type: "Actuator"
    }
    actuator - satisfies -> req_lock

